// ============== APPLY ==============
let s = fs.readFileSync(PATH, 'utf8');

// Process per-lang block. Each lang is a JS object literal like `pt: { ... },`
// Strategy: find each `<lang>: {` block and replace specific keys + inject new at the end (before closing `},`).

for (const lang of Object.keys(UPDATE)) {
  const upd = UPDATE[lang] || {};
  const ne = NEW[lang] || {};

  // Find block start
  const startRe = new RegExp(`(\\b${lang}\\s*:\\s*\\{)`, 'm');
  const startMatch = startRe.exec(s);
  if (!startMatch) { console.warn(`SKIP ${lang}: block not found`); continue; }
  const blockStart = startMatch.index + startMatch[0].length;

  // Find matching closing brace (balanced)
  let depth = 1, i = blockStart;
  while (i < s.length && depth > 0) {
    const c = s[i];
    if (c === '{') depth++;
    else if (c === '}') depth--;
    if (depth === 0) break;
    i++;
  }
  if (depth !== 0) { console.warn(`SKIP ${lang}: unbalanced braces`); continue; }
  const blockEnd = i;

  let block = s.slice(blockStart, blockEnd);

  // 1) UPDATE existing keys
  for (const [k, v] of Object.entries(upd)) {
    const json = JSON.stringify(v);
    // matches: key: 'old value', / key: "old", / key: `old`, until end of line (comma or end)
    const re = new RegExp(`(\\b${k}\\s*:\\s*)(?:'(?:\\\\.|[^'\\\\])*'|"(?:\\\\.|[^"\\\\])*"|\`(?:\\\\.|[^\`\\\\])*\`)`, 'm');
    if (re.test(block)) {
      block = block.replace(re, `$1${json}`);
    } else {
      console.warn(`${lang}: key '${k}' not found, will be appended as new`);
      ne[k] = v;
    }
  }

  // 2) INJECT new keys (before final closing brace of the block)
  let inserts = '';
  for (const [k, v] of Object.entries(ne)) {
    inserts += `\n    ${k}: ${JSON.stringify(v)},`;
  }
  // Ensure trailing comma alignment
  const trimmed = block.replace(/,\s*$/, '');
  block = trimmed + ',' + inserts + '\n  ';

  s = s.slice(0, blockStart) + block + s.slice(blockEnd);

  console.log(`${lang}: updated ${Object.keys(upd).length}, injected ${Object.keys(ne).length}`);
}

fs.writeFileSync(PATH, s, 'utf8');
console.log('\nDone.');
